module top_module(
    input                clk,
    input                reset,
    input                [3:0] adder_in1, // 4-bit input 1 for the adder
    input                [3:0] adder_in2, // 4-bit input 2 for the adder
    input                cin, // Carry-in for the adder
    output               [3:0] out // 4-bit output from the functional module
);// 4-bit adder using combinational logic
    wire [3:0] adder_out;
    wire cout;
      wire _n01 = adder_in1 + adder_in2[0] ^ cin[0];
  wire _c01 = adder_in1 + adder_in2[0] & cin[0];
  wire _n02 = adder_in1 + adder_in2[1] ^ cin[1] ^ _c01;
  wire _c02 = (adder_in1 + adder_in2[1] & cin[1]) | (adder_in1 + adder_in2[1] & _c01) | (cin[1] & _c01);
  wire _n03 = adder_in1 + adder_in2[2] ^ cin[2] ^ _c02;
  wire _c03 = (adder_in1 + adder_in2[2] & cin[2]) | (adder_in1 + adder_in2[2] & _c02) | (cin[2] & _c02);
  wire _n04 = adder_in1 + adder_in2[3] ^ cin[3] ^ _c03;
  wire _c04 = (adder_in1 + adder_in2[3] & cin[3]) | (adder_in1 + adder_in2[3] & _c03) | (cin[3] & _c03);
  assign {cout, adder_out} = {_n01, _n02, _n03, _n04};

    // 4-bit counter with cyclic state sequence
    reg [3:0] counter;
    always @(posedge clk) begin
        if (reset) begin
            counter <= 4'b0000;
        end else begin
            case (counter)
                4'b0000: counter <= 4'b0001;
                4'b0001: counter <= 4'b0011;
                4'b0011: counter <= 4'b0111;
                4'b0111: counter <= 4'b1111;
                4'b1111: counter <= 4'b0000;
            endcase
        end
    end

    // Functional module that outputs the bitwise XOR of the adder and counter
    assign out = adder_out ^ counter;

endmodule
